module RefModule (
    input clk,
    input reset,
    output reg [4:0] q
);

    // Ring counter logic
    always @(posedge clk) begin
        if (reset)
            q <= 5'b00001;
        else
            q <= {q[3:0], q[4]};
    end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
